// 三载体一致：纯 JS、无 DOM/uplink/shadow 足迹
import PF from 'https://cdn.jsdelivr.net/npm/pathfinding@0/+esm';
const finders = { AStar: PF.AStarFinder, BreadthFirst: PF.BreadthFirstFinder, Dijkstra: PF.DijkstraFinder, BiAStar: PF.BiAStarFinder, JumpPoint: PF.JumpPointFinder };
const Finder = finders[data.finder ?? 'AStar'];
const finder = new Finder({ allowDiagonal: data.allowDiagonal ?? false, dontCrossCorners: data.dontCrossCorners ?? false, weight: data.weight ?? 1 });
const grid = new PF.Grid(data.matrix);
const path = finder.findPath(data.start[0], data.start[1], data.goal[0], data.goal[1], grid);
